"use client";
import { useForm } from "react-hook-form";
import { Form } from "@/components/ui/form";
import Screen from "@/components/layout/screen";
import { zodResolver } from "@hookform/resolvers/zod";
import { HajiProduct, hajiProductSchema } from "@/typing/haji-product";
import HajiForm from "./haji_form";
import { useCheckoutHaji } from "@/query/haji";
import { toast } from "sonner";
import { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { useRouter } from "next/navigation";
import { Header } from "@/components/shared";

type State = "process" | "success";

const ContextForm = () => {
  const router = useRouter();
  const [state, setState] = useState<State>("process");
  const { mutateAsync, isPending } = useCheckoutHaji();
  const form = useForm<HajiProduct>({
    resolver: zodResolver(hajiProductSchema),
    defaultValues: {
      produk_id: 1,
      nama_lengkap: "",
      no_whatsapp: "",
      alamat_lengkap: "",
      deskripsi: "",
      gelar_id: 1,
      jamaah_data: [],
    },
    disabled: isPending,
  });

  async function onSubmit(data: HajiProduct) {
    return await mutateAsync(data, {
      onSuccess: () => {
        setState("success");
        toast.success("Submitted successfully!");
      },
      onError: () => toast("Something went wrong, please try again."),
    });
  }

  if (state === "success") {
    return (
      <Screen className="md:py-14">
        <div className="sm:space-y-6">
          <div className="p-4 sm:p-0">
            <Header
              title="Pendaftaran Kamu Sedang Kami Tinjau"
              description="Kami sedang memproses pendaftaran Haji kamu. Mohon tunggu informasi selanjutnya dari kami melalui WhatsApp."
            />
          </div>
          <Card className="rounded-none md:rounded-2xl">
            <CardContent>
              <div className="flex flex-col items-center justify-center">
                <svg
                  width="240"
                  height="240"
                  viewBox="0 0 240 240"
                  fill="none"
                  xmlns="http://www.w3.org/2000/svg"
                  xmlnsXlink="http://www.w3.org/1999/xlink"
                >
                  <rect
                    width="240"
                    height="240"
                    fill="url(#pattern0_3716_28268)"
                  />
                  <defs>
                    <pattern
                      id="pattern0_3716_28268"
                      patternContentUnits="objectBoundingBox"
                      width="1"
                      height="1"
                    >
                      <use
                        xlinkHref="#image0_3716_28268"
                        transform="scale(0.001)"
                      />
                    </pattern>
                    <image
                      id="image0_3716_28268"
                      width="1000"
                      height="1000"
                      preserveAspectRatio="none"
                      xlinkHref="data:image/png;base64,"
                    />
                  </defs>
                </svg>
                <div className="space-y-2 text-center">
                  <p className="text-16 md:text-20 lg:text-14 font-bold">
                    Pendaftaran Haji Kamu Sedang Diproses
                  </p>
                  <p className="text-10 md:text-12 lg:text-14">
                    Kami akan segera memprosesnya dan mengirimkan info
                    selengkapnya ke WhatsApp Kamu setelah dikonfirmasi oleh tim
                    kami.
                  </p>
                </div>
              </div>
            </CardContent>
            <CardContent>
              <div className="p-4 rounded-2xl border-[0.5px]">
                <div className="flex items-center gap-4">
                  <svg
                    width="18"
                    height="18"
                    viewBox="0 0 18 18"
                    fill="none"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path
                      fillRule="evenodd"
                      clipRule="evenodd"
                      d="M18 9C18 4.0293 13.9707 0 9 0C4.0293 0 0 4.0293 0 9C0 13.9707 4.0293 18 9 18C13.9707 18 18 13.9707 18 9ZM9 4.5C9.23869 4.5 9.46761 4.59482 9.6364 4.7636C9.80518 4.93239 9.9 5.1613 9.9 5.4V9.9C9.9 10.1387 9.80518 10.3676 9.6364 10.5364C9.46761 10.7052 9.23869 10.8 9 10.8C8.7613 10.8 8.53239 10.7052 8.3636 10.5364C8.19482 10.3676 8.1 10.1387 8.1 9.9V5.4C8.1 5.1613 8.19482 4.93239 8.3636 4.7636C8.53239 4.59482 8.7613 4.5 9 4.5ZM8.1 12.6C8.1 12.3613 8.19482 12.1324 8.3636 11.9636C8.53239 11.7948 8.7613 11.7 9 11.7H9.0072C9.2459 11.7 9.47481 11.7948 9.6436 11.9636C9.81238 12.1324 9.9072 12.3613 9.9072 12.6C9.9072 12.8387 9.81238 13.0676 9.6436 13.2364C9.47481 13.4052 9.2459 13.5 9.0072 13.5H9C8.7613 13.5 8.53239 13.4052 8.3636 13.2364C8.19482 13.0676 8.1 12.8387 8.1 12.6Z"
                      fill="#EF4444"
                    />
                  </svg>
                  <div className="text-12 md:text-14 lg:text-16">
                    <p className="text-red-500 font-bold">Penting Diketahui</p>
                    <p className="text-khaffah-neutral-dark">
                      Pendaftaran kamu akan kami lanjutkan melalui WhatsApp
                      untuk mengonfirmasi apakah kamu mendapatkan slot
                      keberangkatan Haji.
                    </p>
                  </div>
                </div>
              </div>
            </CardContent>
            <CardContent>
              <button
                onClick={() => router.replace("/")}
                className="bg-khaffah-primary py-2 rounded-xl w-full text-white font-bold text-12 md:text-14 lg:text-16"
                type="button"
              >
                Kembali Ke Beranda
              </button>
            </CardContent>
          </Card>
        </div>
      </Screen>
    );
  }

  return (
    <Screen className="py-14">
      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit)}>
          <HajiForm />
        </form>
      </Form>
    </Screen>
  );
};

export default ContextForm;
